POS_PHRASES = ["great", "excellent", "love", "perfect", "amazing", "highly recommend", "quality", "fantastic", "wonderful", "outstanding"]
NEG_PHRASES = ["disappointed", "poor quality", "waste", "broken", "terrible", "return", "awful", "horrible", "defective", "useless"]
NEU_PHRASES = ["average", "okay", "decent", "nothing special", "as described", "alright", "fine", "mediocre", "expected", "ordinary"]

POS_TEMPLATES = [
    "This product is {p1}! {extra}",
    "I {p1} this item so much. {extra}",
    "Absolutely {p1} purchase. {extra}",
    "{p1} quality and fast shipping. {extra}",
    "I would {p1} this to everyone. {extra}",
]
NEG_TEMPLATES = [
    "Very {p1} product. {extra}",
    "Total {p1} of money. {extra}",
    "I am so {p1} with this purchase. {extra}",
    "The item arrived {p1}. {extra}",
    "This is {p1} and I want to {extra}",
]
NEU_TEMPLATES = [
    "The product is {p1}. {extra}",
    "It's {p1}, {extra}",
    "Pretty {p1} overall. {extra}",
    "{p1} product, {extra}",
    "Exactly {p1}. {extra}",
]

POS_EXTRAS = [
    "Fast shipping and well packaged.",
    "Works exactly as described.",
    "Would buy again without hesitation.",
    "Great value for the price.",
    "Customer service was also helpful.",
]
NEG_EXTRAS = [
    "Requesting a refund immediately.",
    "Do not recommend this seller.",
    "Complete waste of money.",
    "Returning it as soon as possible.",
    "Expected much better quality.",
]
NEU_EXTRAS = [
    "Nothing impressive but does the job.",
    "Would consider other options next time.",
    "Arrived on time at least.",
    "Packaging was adequate.",
    "Might work for some people.",
]


def generate_products():
    rows = []
    pid = 1
    for cat, items in PRODUCTS.items():
        for name, desc in items:
            price = round(random.uniform(5, 500), 2)
            rating = round(random.uniform(1.0, 5.0), 1)
            rows.append({"id": pid, "name": name, "category": cat, "description": desc, "price": price, "rating": rating})
            pid += 1
    return pd.DataFrame(rows)


def random_date():
    start = datetime(2023, 1, 1)
    end = datetime(2024, 12, 31)
    delta = end - start
    return (start + timedelta(days=random.randint(0, delta.days))).strftime("%Y-%m-%d")


def generate_review_text(sentiment):
    if sentiment == "positive":
        p = random.choice(POS_PHRASES)
        tmpl = random.choice(POS_TEMPLATES)
        extra = random.choice(POS_EXTRAS)
        return tmpl.format(p1=p, extra=extra)
    elif sentiment == "negative":
        p = random.choice(NEG_PHRASES)
        tmpl = random.choice(NEG_TEMPLATES)
        extra = random.choice(NEG_EXTRAS)
        return tmpl.format(p1=p, extra=extra)
    else:
        p = random.choice(NEU_PHRASES)
        tmpl = random.choice(NEU_TEMPLATES)
        extra = random.choice(NEU_EXTRAS)
        return tmpl.format(p1=p, extra=extra)


def generate_reviews(n=600):
    sentiments = (["positive"] * 360) + (["negative"] * 150) + (["neutral"] * 90)
    random.shuffle(sentiments)
    rows = []
    for i, sentiment in enumerate(sentiments, 1):
        rows.append({
            "id": i,
            "product_id": random.randint(1, 200),
            "review_text": generate_review_text(sentiment),
            "sentiment": sentiment,
            "date": random_date(),
        })
    return pd.DataFrame(rows)


if __name__ == "__main__":
    os.makedirs("data", exist_ok=True)
    products = generate_products()
    products.to_csv("data/products.csv", index=False)
    print(f"Generated {len(products)} products -> data/products.csv")

    reviews = generate_reviews()
    reviews.to_csv("data/reviews.csv", index=False)
    print(f"Generated {len(reviews)} reviews -> data/reviews.csv")
